import pytest

def test_view_document_missing_mandatory_field_returns_400(manager_client, valid_document_payload, audit_log_reader):
    incomplete_payload = {k: v for k, v in valid_document_payload.items() if k != "title"}
    response = manager_client.post("/documents", json=incomplete_payload)
    assert response.status_code == 400, (
        f"Expected 400, got {response.status_code}"
    )
    body = response.json()
    error_text = str(body)
    assert "title" in error_text.lower(), (
        "Validation error must reference the missing 'title' field"
    )
    audit_entries = audit_log_reader.fetch_recent(seconds=5)
    assert len(audit_entries) == 0, (
        "No audit record should be written when validation fails"
    )
